import EncryptedStorage from 'react-native-encrypted-storage';
import * as Keychain from 'react-native-keychain';
import CryptoJS from 'crypto-js';
import { v4 as uuidv4 } from 'uuid';
import { PaymentConfig } from '../config/payment.config';

class SecurityManager {
  static instance = null;

  static getInstance() {
    if (!SecurityManager.instance) {
      SecurityManager.instance = new SecurityManager();
    }
    return SecurityManager.instance;
  }

  constructor() {
    this._sessionToken = null;
    this._deviceFingerprint = null;
    this._encryptionKey = PaymentConfig.security.encryptionKey;
  }

  // Encrypt sensitive data before transmission or storage
  encrypt(data) {
    try {
      const dataString = typeof data === 'string' ? data : JSON.stringify(data);
      const iv = CryptoJS.lib.WordArray.random(16);
      const encrypted = CryptoJS.AES.encrypt(dataString, this._encryptionKey, {
        iv: iv,
        mode: CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7,
      });
      return {
        ciphertext: encrypted.toString(),
        iv: iv.toString(CryptoJS.enc.Hex),
        timestamp: Date.now(),
      };
    } catch (error) {
      throw new PaymentSecurityError('Encryption failed', error);
    }
  }

  // Decrypt sensitive data
  decrypt(encryptedData) {
    try {
      const { ciphertext, iv } = encryptedData;
      const decrypted = CryptoJS.AES.decrypt(ciphertext, this._encryptionKey, {
        iv: CryptoJS.enc.Hex.parse(iv),
        mode: CryptoJS.mode.CBC,
        padding: CryptoJS.pad.Pkcs7,
      });
      return JSON.parse(decrypted.toString(CryptoJS.enc.Utf8));
    } catch (error) {
      throw new PaymentSecurityError('Decryption failed', error);
    }
  }

  // Generate HMAC signature for request integrity
  generateSignature(payload) {
    const dataString = typeof payload === 'string' ? payload : JSON.stringify(payload);
    return CryptoJS.HmacSHA256(dataString, this._encryptionKey).toString(CryptoJS.enc.Hex);
  }

  // Verify HMAC signature
  verifySignature(payload, signature) {
    const expectedSignature = this.generateSignature(payload);
    return expectedSignature === signature;
  }

  // Store payment tokens securely
  async storePaymentToken(tokenKey, tokenValue) {
    try {
      const encryptedToken = this.encrypt(tokenValue);
      await EncryptedStorage.setItem(
        `payment_token_${tokenKey}`,
        JSON.stringify({
          ...encryptedToken,
          expiresAt: Date.now() + PaymentConfig.security.tokenExpiry * 1000,
        })
      );
      return true;
    } catch (error) {
      throw new PaymentSecurityError('Failed to store payment token', error);
    }
  }

  // Retrieve payment tokens securely
  async retrievePaymentToken(tokenKey) {
    try {
      const stored = await EncryptedStorage.getItem(`payment_token_${tokenKey}`);
      if (!stored) return null;

      const parsed = JSON.parse(stored);
      if (Date.now() > parsed.expiresAt) {
        await this.removePaymentToken(tokenKey);
        return null;
      }

      return this.decrypt(parsed);
    } catch (error) {
      throw new PaymentSecurityError('Failed to retrieve payment token', error);
    }
  }

  // Remove payment token
  async removePaymentToken(tokenKey) {
    try {
      await EncryptedStorage.removeItem(`payment_token_${tokenKey}`);
    } catch (error) {
      console.warn('Failed to remove payment token:', error);
    }
  }

  // Store credentials in Keychain
  async storeCredentials(service, username, password) {
    try {
      await Keychain.setGenericPassword(username, password, { service });
      return true;
    } catch (error) {
      throw new PaymentSecurityError('Failed to store credentials', error);
    }
  }

  // Retrieve credentials from Keychain
  async retrieveCredentials(service) {
    try {
      const credentials = await Keychain.getGenericPassword({ service });
      return credentials || null;
    } catch (error) {
      throw new PaymentSecurityError('Failed to retrieve credentials', error);
    }
  }

  // Generate idempotency key for payment requests
  generateIdempotencyKey() {
    return `idem_${uuidv4()}_${Date.now()}`;
  }

  // Generate device fingerprint for fraud detection
  async getDeviceFingerprint() {
    if (this._deviceFingerprint) return this._deviceFingerprint;

    const fingerprintData = {
      timestamp: Date.now(),
      random: uuidv4(),
    };

    this._deviceFingerprint = CryptoJS.SHA256(
      JSON.stringify(fingerprintData)
    ).toString(CryptoJS.enc.Hex);

    return this._deviceFingerprint;
  }

  // Sanitize sensitive data for logging
  sanitize(data) {
    const sensitiveFields = [
      'cardNumber', 'cvv', 'cvc', 'pin', 'password',
      'token', 'secret', 'ssn', 'accountNumber',
    ];

    if (typeof data !== 'object' || data === null) return data;

    const sanitized = { ...data };
    for (const field of sensitiveFields) {
      if (sanitized[field]) {
        const value = String(sanitized[field]);
        sanitized[field] = value.length > 4
          ? `****${value.slice(-4)}`
          : '****';
      }
    }
    return sanitized;
  }

  // Clear all stored payment data
  async clearAllPaymentData() {
    try {
      const keys = ['payment_token_stripe', 'payment_token_wallet', 'payment_token_session'];
      await Promise.all(keys.map((key) => EncryptedStorage.removeItem(key)));
      await Keychain.resetGenericPassword({ service: 'payment_service' });
      this._sessionToken = null;
      this._deviceFingerprint = null;
    } catch (error) {
      console.warn('Failed to clear all payment data:', error);
    }
  }
}

class PaymentSecurityError extends Error {
  constructor(message, originalError) {
    super(message);
    this.name = 'PaymentSecurityError';
    this.originalError = originalError;
  }
}

