// src/api/PaymentApiClient.js
import { SecurityManager } from '../security/SecurityManager';
import { PaymentConfig } from '../config/payment.config';

class PaymentApiClient {
  constructor() {
    this.security = SecurityManager.getInstance();
    this.baseUrl = PaymentConfig.api.baseUrl;
    this.timeout = PaymentConfig.security.requestTimeout;
    this.maxRetries = PaymentConfig.security.maxRetries;
  }

  async request(endpoint, method = 'GET', body = null, retryCount = 0) {
    const url = `${this.baseUrl}${endpoint}`;
    const idempotencyKey = this.security.generateIdempotencyKey();
    const deviceFingerprint = await this.security.getDeviceFingerprint();
    const sessionToken = await this.security.retrievePaymentToken('session');

    const headers = {
      'Content-Type': 'application/json',
      'X-Idempotency-Key': idempotencyKey,
      'X-Device-Fingerprint': deviceFingerprint,
      'X-Request-Timestamp': Date.now().toString(),
    };

    if (sessionToken) {
      headers['Authorization'] = `Bearer ${sessionToken}`;
    }

    if (body) {
      const signature = this.security.generateSignature(body);
      headers['X-Signature'] = signature;
    }

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), this.timeout);

    try {
      const response = await fetch(url, {
        method,
        headers,
        body: body ? JSON.stringify(body) : null,
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const errorBody = await response.json().catch(() => ({}));
        throw new PaymentApiError(
          errorBody.message || `HTTP ${response.status}`,
          response.status,
          errorBody.code
        );
      }

      const responseData = await response.json();

      // Verify response signature if present
      const responseSignature = response.headers.get('X-Response-Signature');
      if (responseSignature) {
        const isValid = this.security.verifySignature(responseData, responseSignature);
        if (!isValid) {
          throw new PaymentApiError('Response signature verification failed', 0, 'SIGNATURE_INVALID');
        }
      }

      return responseData;
    } catch (error) {
      clearTimeout(timeoutId);

      if (error.name === 'AbortError') {
        throw new PaymentApiError('Request timeout', 0, 'TIMEOUT');
      }

      // Retry on network errors or 5xx
      if (
        retryCount < this.maxRetries &&
        (error.statusCode >= 500 || error.code === 'TIMEOUT' || !error.statusCode)
      ) {
        const delay = Math.pow(2, retryCount) * 1000 + Math.random() * 1000;
        await new Promise((resolve) => setTimeout(resolve, delay));
        return this.request(endpoint, method, body, retryCount + 1);
      }

      throw error;
    }
  }

  async createPaymentIntent(amount, currency, metadata = {}) {
    return this.request(
      PaymentConfig.api.endpoints.createPaymentIntent,
      'POST',
      { amount, currency, metadata }
    );
  }

  async verifyReceipt(receipt, platform) {
    const encryptedReceipt = this.security.encrypt(receipt);
    return this.request(
      PaymentConfig.api.endpoints.verifyReceipt,
      'POST',
      { receipt: encryptedReceipt, platform }
    );
  }

  async processWalletPayment(walletType, paymentData) {
    return this.request(
      PaymentConfig.api.endpoints.processWalletPayment,
      'POST',
      { walletType, paymentData }
    );
  }

  async requestRefund(transactionId, reason) {
    return this.request(
      PaymentConfig.api.endpoints.refund,
      'POST',
      { transactionId, reason }
    );
  }

  async getTransactionHistory(page = 1, limit = 20) {
    return this.request(
      `${PaymentConfig.api.endpoints.transactionHistory}?page=${page}&limit=${limit}`,
      'GET'
    );
  }
}

class PaymentApiError extends Error {
  constructor(message, statusCode, code) {
    super(message);
    this.name = 'PaymentApiError';
    this.statusCode = statusCode;
    this.code = code;
  }
}

