// src/services/IAPService.js
import { Platform } from 'react-native';
import {
  initConnection,
  endConnection,
  getProducts,
  getSubscriptions,
  requestPurchase,
  requestSubscription,
  finishTransaction,
  purchaseUpdatedListener,
  purchaseErrorListener,
  getAvailablePurchases,
  acknowledgePurchaseAndroid,
  clearTransactionIOS,
  validateReceiptIos,
  flushFailedPurchasesCachedAsPendingAndroid,
} from 'react-native-iap';
import { PaymentApiClient } from '../api/PaymentApiClient';
import { SecurityManager } from '../security/SecurityManager';
import { PaymentConfig } from '../config/payment.config';

class IAPService {
  static instance = null;

  static getInstance() {
    if (!IAPService.instance) {
      IAPService.instance = new IAPService();
    }
    return IAPService.instance;
  }

  constructor() {
    this.apiClient = new PaymentApiClient();
    this.security = SecurityManager.getInstance();
    this.isInitialized = false;
    this.products = [];
    this.subscriptions = [];
    this.purchaseUpdateSubscription = null;
    this.purchaseErrorSubscription = null;
    this._purchaseListeners = [];
    this._errorListeners = [];
  }

  // Initialize IAP connection
  async initialize() {
    if (this.isInitialized) return;

    try {
      const result = await initConnection();
      console.log('IAP Connection initialized:', result);

      if (Platform.OS === 'android') {
        await flushFailedPurchasesCachedAsPendingAndroid();
      }

      // Set up purchase listeners
      this.purchaseUpdateSubscription = purchaseUpdatedListener(
        async (purchase) => {
          await this._handlePurchaseUpdate(purchase);
        }
      );

      this.purchaseErrorSubscription = purchaseErrorListener(
        (error) => {
          this._handlePurchaseError(error);
        }
      );

      this.isInitialized = true;
    } catch (error) {
      throw new IAPError('Failed to initialize IAP', error);
    }
  }

  // Clean up IAP connection
  async dispose() {
    if (this.purchaseUpdateSubscription) {
      this.purchaseUpdateSubscription.remove();
      this.purchaseUpdateSubscription = null;
    }
    if (this.purchaseErrorSubscription) {
      this.purchaseErrorSubscription.remove();
      this.purchaseErrorSubscription = null;
    }

    try {
      await endConnection();
    } catch (error) {
      console.warn('Error ending IAP connection:', error);
    }

    this.isInitialized = false;
  }

  // Register purchase listener
  addPurchaseListener(listener) {
    this._purchaseListeners.push(listener);
    return () => {
      this._purchaseListeners = this._purchaseListeners.filter((l) => l !== listener);
    };
  }

  // Register error listener
  addErrorListener(listener) {
    this._errorListeners.push(listener);
    return () => {
      this._errorListeners = this._errorListeners.filter((l) => l !== listener);
    };
  }

  // Fetch available products
  async fetchProducts() {
    await this._ensureInitialized();

    try {
      const productIds = [
        ...PaymentConfig.products.consumables,
        ...PaymentConfig.products.nonConsumables,
      ];

      this.products = await getProducts({ skus: productIds });
      return this.products;
    } catch (error) {
      throw new IAPError('Failed to fetch products', error);
    }
  }

  // Fetch available subscriptions
  async fetchSubscriptions() {
    await this._ensureInitialized();

    try {
      this.subscriptions = await getSubscriptions({
        skus: PaymentConfig.products.subscriptions,
      });
      return this.subscriptions;
    } catch (error) {
      throw new IAPError('Failed to fetch subscriptions', error);
    }
  }

  // Purchase a product
  async purchaseProduct(productId, isConsumable = false) {
    await this._ensureInitialized();

    try {
      if (Platform.OS === 'ios') {
        await requestPurchase({ sku: productId, andDangerouslyFinishTransactionAutomaticallyIOS: false });
      } else {
        await requestPurchase({
          skus: [productId],
          obfuscatedAccountIdAndroid: await this.security.getDeviceFingerprint(),
        });
      }
      // Purchase result will be handled by purchaseUpdatedListener
    } catch (error) {
      if (error.code === 'E_USER_CANCELLED') {
        throw new IAPError('Purchase cancelled by user', error, 'USER_CANCELLED');
      }
      throw new IAPError('Purchase failed', error);
    }
  }

  // Purchase a subscription
  async purchaseSubscription(subscriptionId, offerToken = null) {
    await this._ensureInitialized();

    try {
      const purchaseParams = Platform.OS === 'ios'
        ? { sku: subscriptionId, andDangerouslyFinishTransactionAutomaticallyIOS: false }
        : {
            sku: subscriptionId,
            ...(offerToken ? { subscriptionOffers: [{ sku: subscriptionId, offerToken }] } : {}),
            obfuscatedAccountIdAndroid: await this.security.getDeviceFingerprint(),
          };

      await requestSubscription(purchaseParams);
    } catch (error) {
      if (error.code === 'E_USER_CANCELLED') {
        throw new IAPError('Subscription cancelled by user', error, 'USER_CANCELLED');
      }
      throw new IAPError('Subscription purchase failed', error);
    }
  }

  // Restore previous purchases
  async restorePurchases() {
    await this._ensureInitialized();

    try {
      const purchases = await getAvailablePurchases();
      const verifiedPurchases = [];

      for (const purchase of purchases) {
        try {
          const verification = await this._verifyPurchaseWithServer(purchase);
          if (verification.isValid) {
            verifiedPurchases.push({
              ...purchase,
              serverVerification: verification,
            });
          }
        } catch (verifyError) {
          console.warn('Failed to verify restored purchase:', verifyError);
        }
      }

      return verifiedPurchases;
    } catch (error) {
      throw new IAPError('Failed to restore purchases', error);
    }
  }

  // Handle purchase update from listener
  async _handlePurchaseUpdate(purchase) {
    try {
      const receipt = Platform.OS === 'ios'
        ? purchase.transactionReceipt
        : purchase.purchaseToken;

      if (!receipt) {
        throw new Error('No receipt found in purchase');
      }

      // Verify with server
      const verification = await this._verifyPurchaseWithServer(purchase);

      if (verification.isValid) {
        // Finish the transaction
        await this._finishPurchase(purchase);

        // Store purchase info securely
        await this.security.storePaymentToken(
          `purchase_${purchase.productId}`,
          {
            productId: purchase.productId,
            transactionId: purchase.transactionId,
            purchaseDate: purchase.transactionDate,
            verified: true,
          }
        );

        // Notify listeners
        this._purchaseListeners.forEach((listener) =>
          listener({
            type: 'PURCHASE_SUCCESS',
            purchase,
            verification,
          })
        );
      } else {
        throw new Error('Server verification failed');
      }
    } catch (error) {
      console.error('Purchase update handling failed:', error);
      this._errorListeners.forEach((listener) =>
        listener({
          type: 'VERIFICATION_FAILED',
          purchase,
          error,
        })
      );
    }
  }

  // Handle purchase errors from listener
  _handlePurchaseError(error) {
    console.error('Purchase error:', error);
    this._errorListeners.forEach((listener) =>
      listener({
        type: 'PURCHASE_ERROR',
        error,
      })
    );
  }

  // Verify purchase with backend server
  async _verifyPurchaseWithServer(purchase) {
    const receipt = Platform.OS === 'ios'
      ? purchase.transactionReceipt
      : purchase.purchaseToken;

    return this.apiClient.verifyReceipt(
      {
        receipt,
        productId: purchase.productId,
        transactionId: purchase.transactionId,
        platform: Platform.OS,
      },
      Platform.OS
    );
  }

  // Finish / acknowledge the purchase
  async _finishPurchase(purchase) {
    try {
      if (Platform.OS === 'ios') {
        await finishTransaction({ purchase, isConsumable: true });
      } else {
        if (purchase.purchaseStateAndroid === 1 && !purchase.isAcknowledgedAndroid) {
          await acknowledgePurchaseAndroid({ token: purchase.purchaseToken });
        }
        await finishTransaction({ purchase, isConsumable: true });
      }
    } catch (error) {
      console.error('Failed to finish transaction:', error);
      throw new IAPError('Failed to finish transaction', error);
    }
  }

  async _ensureInitialized() {
    if (!this.isInitialized) {
      await this.initialize();
    }
  }
}

class IAPError extends Error {
  constructor(message, originalError, code = 'IAP_ERROR') {
    super(message);
    this.name = 'IAPError';
    this.code = code;
    this.originalError = originalError;
  }
}

export { IAPService, IAPError };

