// src/services/DigitalWalletService.js
import { Platform } from 'react-native';
import {
  isPlatformPaySupported,
  confirmPlatformPayPayment,
  createPlatformPayPaymentMethod,
  PlatformPay,
} from '@stripe/stripe-react-native';
import { PaymentApiClient } from '../api/PaymentApiClient';
import { SecurityManager } from '../security/SecurityManager';
import { PaymentConfig } from '../config/payment.config';

class DigitalWalletService {
  static instance = null;

  static getInstance() {
    if (!DigitalWalletService.instance) {
      DigitalWalletService.instance = new DigitalWalletService();
    }
    return DigitalWalletService.instance;
  }

  constructor() {
    this.apiClient = new PaymentApiClient();
    this.security = SecurityManager.getInstance();
    this._isApplePaySupported = null;
    this._isGooglePaySupported = null;
  }

  // Check if Apple Pay is available
  async isApplePayAvailable() {
    if (Platform.OS !== 'ios') return false;
    if (this._isApplePaySupported !== null) return this._isApplePaySupported;

    try {
      this._isApplePaySupported = await isPlatformPaySupported();
      return this._isApplePaySupported;
    } catch (error) {
      console.warn('Apple Pay check failed:', error);
      return false;
    }
  }

  // Check if Google Pay is available
  async isGooglePayAvailable() {
    if (Platform.OS !== 'android') return false;
    if (this._isGooglePaySupported !== null) return this._isGooglePaySupported;

    try {
      this._isGooglePaySupported = await isPlatformPaySupported({
        googlePay: {
          testEnv: __DEV__,
          existingPaymentMethodRequired: false,
        },
      });
      return this._isGooglePaySupported;
    } catch (error) {
      console.warn('Google Pay check failed:', error);
      return false;
    }
  }

  // Check if any digital wallet is available
  async isWalletAvailable() {
    if (Platform.OS === 'ios') return this.isApplePayAvailable();
    if (Platform.OS === 'android') return this.isGooglePayAvailable();
    return false;
  }

  // Process Apple Pay payment
  async payWithApplePay(amount, currency, description, items = []) {
    if (!(await this.isApplePayAvailable())) {
      throw new WalletError('Apple Pay is not available on this device');
    }

    try {
      // Create payment intent on server
      const { clientSecret } = await this.apiClient.createPaymentIntent(
        Math.round(amount * 100),
        currency,
        {
          walletType: 'apple_pay',
          description,
          deviceFingerprint: await this.security.getDeviceFingerprint(),
        }
      );

      const cartItems = items.length > 0
        ? items.map((item) => ({
            label: item.label,
            amount: item.amount.toString(),
            paymentType: PlatformPay.PaymentType.Immediate,
          }))
        : [
            {
              label: description,
              amount: amount.toString(),
              paymentType: PlatformPay.PaymentType.Immediate,
            },
          ];

      const { error, paymentIntent } = await confirmPlatformPayPayment(clientSecret, {
        applePay: {
          cartItems,
          merchantCountryCode: 'US',
          currencyCode: currency.toUpperCase(),
          requiredBillingContactFields: [
            PlatformPay.ContactField.PhoneNumber,
            PlatformPay.ContactField.EmailAddress,
          ],
        },
      });

      if (error) {
        throw new WalletError(`Apple Pay failed: ${error.message}`, error.code);
      }

      // Store transaction securely
      await this._storeTransaction({
        type: 'apple_pay',
        paymentIntentId: paymentIntent.id,
        amount,
        currency,
        status: paymentIntent.status,
        timestamp: Date.now(),
      });

      return {
        success: true,
        transactionId: paymentIntent.id,
        status: paymentIntent.status,
        amount,
        currency,
        walletType: 'apple_pay',
      };
    } catch (error) {
      if (error instanceof WalletError) throw error;
      throw new WalletError('Apple Pay payment failed', error.code, error);
    }
  }

  // Process Google Pay payment
  async payWithGooglePay(amount, currency, description) {
    if (!(await this.isGooglePayAvailable())) {
      throw new WalletError('Google Pay is not available on this device');
    }

    try {
      // Create payment intent on server
      const { clientSecret } = await this.apiClient.createPaymentIntent(
        Math.round(amount * 100),
        currency,
        {
          walletType: 'google_pay',
          description,
          deviceFingerprint: await this.security.getDeviceFingerprint(),
        }
      );

      const { error, paymentIntent } = await confirmPlatformPayPayment(clientSecret, {
        googlePay: {
          testEnv: __DEV__,
          merchantName: 'Your App Name',
          merchantCountryCode: 'US',
          currencyCode: currency.toUpperCase(),
          billingAddressConfig: {
            isRequired: true,
            format: PlatformPay.BillingAddressFormat.Full,
            isPhoneNumberRequired: true,
          },
        },
      });

      if (error) {
        throw new WalletError(`Google Pay failed: ${error.message}`, error.code);
      }

      await this._storeTransaction({
        type: 'google_pay',
        paymentIntentId: paymentIntent.id,
        amount,
        currency,
        status: paymentIntent.status,
        timestamp: Date.now(),
      });

      return {
        success: true,
        transactionId: paymentIntent.id,
        status: paymentIntent.status,
        amount,
        currency,
        walletType: 'google_pay',
      };
    } catch (error) {
      if (error instanceof WalletError) throw error;
      throw new WalletError('Google Pay payment failed', error.code, error);
    }
  }

  // Unified wallet payment method
  async payWithWallet(amount, currency, description, items = []) {
    if (Platform.OS === 'ios') {
      return this.payWithApplePay(amount, currency, description, items);
    } else if (Platform.OS === 'android') {
      return this.payWithGooglePay(amount, currency, description);
    }
    throw new WalletError('Digital wallet not supported on this platform');
  }

  // Create a payment method token for recurring payments
  async createWalletPaymentMethod() {
    try {
      if (Platform.OS === 'ios') {
        const { error, paymentMethod } = await createPlatformPayPaymentMethod({
          applePay: {
            cartItems: [
              {
                label: 'Setup',
                amount: '0.00',
                paymentType: PlatformPay.PaymentType.Immediate,
              },
            ],
            merchantCountryCode: 'US',
            currencyCode: 'USD',
          },
        });

        if (error) throw new WalletError(error.message, error.code);
        return paymentMethod;
      } else {
        const { error, paymentMethod } = await createPlatformPayPaymentMethod({
          googlePay: {
            testEnv: __DEV__,
            merchantName: 'Your App Name',
            merchantCountryCode: 'US',
            currencyCode: 'USD',
            existingPaymentMethodRequired: false,
          },
        });

        if (error) throw new WalletError(error.message, error.code);
        return paymentMethod;
      }
    } catch (error) {
      if (error instanceof WalletError) throw error;
      throw new WalletError('Failed to create wallet payment method', null, error);
    }
  }

  // Store transaction record securely
  async _storeTransaction(transaction) {
    try {
      const existingHistory = await this.security.retrievePaymentToken('transaction_history');
      const history = existingHistory || [];
      history.push(transaction);

      // Keep last 100 transactions locally
      const trimmed = history.slice(-100);
      await this.security.storePaymentToken('transaction_history', trimmed);
    } catch (error) {
      console.warn('Failed to store transaction locally:', error);
    }
  }
}

class WalletError extends Error {
  constructor(message, code, originalError) {
    super(message);
    this.name = 'WalletError';
    this.code = code;
    this.originalError = originalError;
  }
}

export { DigitalWalletService, WalletError };

