// 7. Stripe Card Payment Service
// ============================================

// src/services/StripeCardService.js
import {
  confirmPayment,
  createPaymentMethod,
  handleNextAction,
} from '@stripe/stripe-react-native';
import { PaymentApiClient } from '../api/PaymentApiClient';
import { SecurityManager } from '../security/SecurityManager';

class StripeCardService {
  static instance = null;

  static getInstance() {
    if (!StripeCardService.instance) {
      StripeCardService.instance = new StripeCardService();
    }
    return StripeCardService.instance;
  }

  constructor() {
    this.apiClient = new PaymentApiClient();
    this.security = SecurityManager.getInstance();
  }

  // Process card payment using Stripe's CardField
  async payWithCard(amount, currency, billingDetails = {}) {
    try {
      // Create payment intent on server
      const { clientSecret } = await this.apiClient.createPaymentIntent(
        Math.round(amount * 100),
        currency,
        {
          paymentMethod: 'card',
          deviceFingerprint: await this.security.getDeviceFingerprint(),
        }
      );

      // Confirm payment with card details (collected via CardField component)
      const { error, paymentIntent } = await confirmPayment(clientSecret, {
        paymentMethodType: 'Card',
        paymentMethodData: {
          billingDetails,
        },
      });

      if (error) {
        throw new CardPaymentError(error.message, error.code, error.declineCode);
      }

      // Handle 3D Secure / SCA
      if (paymentIntent.status === 'requires_action') {
        const { error: actionError, paymentIntent: updatedIntent } =
          await handleNextAction(clientSecret);

        if (actionError) {
          throw new CardPaymentError(
            'Authentication failed',
            actionError.code,
            actionError.declineCode
          );
        }

        return {
          success: true,
          transactionId: updatedIntent.id,
          status: updatedIntent.status,
          amount,
          currency,
          requiresAction: true,
        };
      }

      return {
        success: true,
        transactionId: paymentIntent.id,
        status: paymentIntent.status,
        amount,
        currency,
      };
    } catch (error) {
      if (error instanceof CardPaymentError) throw error;
      throw new CardPaymentError('Card payment failed', 'UNKNOWN', null, error);
    }
  }

  // Save card for future use
  async saveCard(billingDetails = {}) {
    try {
      const { error, paymentMethod } = await createPaymentMethod({
        paymentMethodType: 'Card',
        paymentMethodData: {
          billingDetails,
        },
      });

      if (error) {
        throw new CardPaymentError(error.message, error.code);
      }

      // Store payment method reference securely
      await this.security.storePaymentToken(`card_${paymentMethod.id}`, {
        id: paymentMethod.id,
        brand: paymentMethod.Card?.brand,
        last4: paymentMethod.Card?.last4,
        expiryMonth: paymentMethod.Card?.expMonth,
        expiryYear: paymentMethod.Card?.expYear,
        createdAt: Date.now(),
      });

      return {
        paymentMethodId: paymentMethod.id,
        brand: paymentMethod.Card?.brand,
        last4: paymentMethod.Card?.last4,
        expiryMonth: paymentMethod.Card?.expMonth,
        expiryYear: paymentMethod.Card?.expYear,
      };
    } catch (error) {
      if (error instanceof CardPaymentError) throw error;
      throw new CardPaymentError('Failed to save card', 'UNKNOWN', null, error);
    }
  }

  // Charge a saved card
  async chargesSavedCard(paymentMethodId, amount, currency) {
    try {
      const { clientSecret } = await this.apiClient.createPaymentIntent(
        Math.round(amount * 100),
        currency,
        {
          paymentMethodId,
          offSession: true,
          deviceFingerprint: await this.security.getDeviceFingerprint(),
        }
      );

      const { error, paymentIntent } = await confirmPayment(clientSecret, {
        paymentMethodType: 'Card',
      });

      if (error) {
        throw new CardPaymentError(error.message, error.code, error.declineCode);
      }

      return {
        success: true,
        transactionId: paymentIntent.id,
        status: paymentIntent.status,
        amount,
        currency,
      };
    } catch (error) {
      if (error instanceof CardPaymentError) throw error;
      throw new CardPaymentError('Saved card charge failed', 'UNKNOWN', null, error);
    }
  }
}

class CardPaymentError extends Error {
  constructor(message, code, declineCode, originalError) {
    super(message);
    this.name = 'CardPaymentError';
    this.code = code;
    this.declineCode = declineCode;
    this.originalError = originalError;
  }
}

export { StripeCardService, CardPaymentError };

