// src/context/PaymentContext.js
import React, { createContext, useContext, useReducer, useCallback, useEffect, useRef } from 'react';
import { Platform } from 'react-native';
import { StripeProvider } from '@stripe/stripe-react-native';
import { IAPService } from '../services/IAPService';
import { DigitalWalletService } from '../services/DigitalWalletService';
import { StripeCardService } from '../services/StripeCardService';
import { SecurityManager } from '../security/SecurityManager';
import { PaymentConfig } from '../config/payment.config';

// Action types
const PAYMENT_ACTIONS = {
  SET_LOADING: 'SET_LOADING',
  SET_ERROR: 'SET_ERROR',
  CLEAR_ERROR: 'CLEAR_ERROR',
  SET_PRODUCTS: 'SET_PRODUCTS',
  SET_SUBSCRIPTIONS: 'SET_SUBSCRIPTIONS',
  SET_WALLET_AVAILABLE: 'SET_WALLET_AVAILABLE',
  SET_TRANSACTION_RESULT: 'SET_TRANSACTION_RESULT',
  CLEAR_TRANSACTION: 'CLEAR_TRANSACTION',
  SET_INITIALIZED: 'SET_INITIALIZED',
  SET_PROCESSING: 'SET_PROCESSING',
  ADD_TRANSACTION_HISTORY: 'ADD_TRANSACTION_HISTORY',
  SET_SAVED_CARDS: 'SET_SAVED_CARDS',
};

const initialState = {
  isInitialized: false,
  isLoading: false,
  isProcessing: false,
  error: null,
  products: [],
  subscriptions: [],
  isWalletAvailable: false,
  walletType: null,
  lastTransaction: null,
  transactionHistory: [],
  savedCards: [],
};

function paymentReducer(state, action) {
  switch (action.type) {
    case PAYMENT_ACTIONS.SET_LOADING:
      return { ...state, isLoading: action.payload };
    case PAYMENT_ACTIONS.SET_PROCESSING:
      return { ...state, isProcessing: action.payload };
    case PAYMENT_ACTIONS.SET_ERROR:
      return { ...state, error: action.payload, isLoading: false, isProcessing: false };
    case PAYMENT_ACTIONS.CLEAR_ERROR:
      return { ...state, error: null };
    case PAYMENT_ACTIONS.SET_PRODUCTS:
      return { ...state, products: action.payload };
    case PAYMENT_ACTIONS.SET_SUBSCRIPTIONS:
      return { ...state, subscriptions: action.payload };
    case PAYMENT_ACTIONS.SET_WALLET_AVAILABLE:
      return {
        ...state,
        isWalletAvailable: action.payload.available,
        walletType: action.payload.type,
      };
    case PAYMENT_ACTIONS.SET_TRANSACTION_RESULT:
      return {
        ...state,
        lastTransaction: action.payload,
        isProcessing: false,
        transactionHistory: [action.payload, ...state.transactionHistory],
      };
    case PAYMENT_ACTIONS.CLEAR_TRANSACTION:
      return { ...state, lastTransaction: null };
    case PAYMENT_ACTIONS.SET_INITIALIZED:
      return { ...state, isInitialized: action.payload, isLoading: false };
    case PAYMENT_ACTIONS.ADD_TRANSACTION_HISTORY:
      return {
        ...state,
        transactionHistory: [...action.payload, ...state.transactionHistory],
      };
    case PAYMENT_ACTIONS.SET_SAVED_CARDS:
      return { ...state, savedCards: action.payload };
    default:
      return state;
  }
}

const PaymentContext = createContext(null);

export function PaymentProvider({ children }) {
  const [state, dispatch] = useReducer(paymentReducer, initialState);
  const iapService = useRef(IAPService.getInstance()).current;
  const walletService = useRef(DigitalWalletService.getInstance()).current;
  const cardService = useRef(StripeCardService.getInstance()).current;
  const security = useRef(SecurityManager.getInstance()).current;

  // Initialize all payment services
  const initializePayments = useCallback(async () => {
    dispatch({ type: PAYMENT_ACTIONS.SET_LOADING, payload: true });

    try {
      // Initialize IAP
      await iapService.initialize();

      // Check wallet availability
      const walletAvailable = await walletService.isWalletAvailable();
      dispatch({
        type: PAYMENT_ACTIONS.SET_WALLET_AVAILABLE,
        payload: {
          available: walletAvailable,
          type: Platform.OS === 'ios' ? 'apple_pay' : 'google_pay',
        },
      });

      // Fetch products and subscriptions
      const [products, subscriptions] = await Promise.allSettled([
        iapService.fetchProducts(),
        iapService.fetchSubscriptions(),
      ]);

      if (products.status === 'fulfilled') {
        dispatch({ type: PAYMENT_ACTIONS.SET_PRODUCTS, payload: products.value });
      }

      if (subscriptions.status === 'fulfilled') {
        dispatch({ type: PAYMENT_ACTIONS.SET_SUBSCRIPTIONS, payload: subscriptions.value });
      }

      dispatch({ type: PAYMENT_ACTIONS.SET_INITIALIZED, payload: true });
    } catch (error) {
      dispatch({
        type: PAYMENT_ACTIONS.SET_ERROR,
        payload: { message: 'Failed to initialize payments', details: error.message },
      });
      dispatch({ type: PAYMENT_ACTIONS.SET_INITIALIZED, payload: false });
    }
  }, [iapService, walletService]);

  // Purchase IAP product
  const purchaseProduct = useCallback(
    async (productId, isConsumable = false) => {
      dispatch({ type: PAYMENT_ACTIONS.CLEAR_ERROR });
      dispatch({ type: PAYMENT_ACTIONS.SET_PROCESSING, payload: true });

      try {
        await iapService.purchaseProduct(productId, isConsumable);
        // Result handled via listener
      } catch (error) {
        dispatch({
          type: PAYMENT_ACTIONS.SET_ERROR,
          payload: {
            message: error.message,
            code: error.code,
            type: 'iap',
          },
        });
      }
    },
    [iapService]
  );

  // Purchase IAP subscription
  const purchaseSubscription = useCallback(
    async (subscriptionId, offerToken) => {
      dispatch({ type: PAYMENT_ACTIONS.CLEAR_ERROR });
      dispatch({ type: PAYMENT_ACTIONS.SET_PROCESSING, payload: true });

      try {
        await iapService.purchaseSubscription(subscriptionId, offerToken);
        // Result handled via listener
      } catch (error) {
        dispatch({
          type: PAYMENT_ACTIONS.SET_ERROR,
          payload: {
            message: error.message,
            code: error.code,
            type: 'subscription',
          },
        });
      }
    },
    [iapService]
  );

  // Pay with digital wallet
  const payWithWallet = useCallback(
    async (amount, currency, description, items) => {
      dispatch({ type: PAYMENT_ACTIONS.CLEAR_ERROR });
      dispatch({ type: PAYMENT_ACTIONS.SET_PROCESSING, payload: true });

      try {
        const result = await walletService.payWithWallet(amount, currency, description, items);
        dispatch({
          type: PAYMENT_ACTIONS.SET_TRANSACTION_RESULT,
          payload: result,
        });
        return result;
      } catch (error) {
        dispatch({
          type: PAYMENT_ACTIONS.SET_ERROR,
          payload: {
            message: error.message,
            code: error.code,
            type: 'wallet',
          },
        });
        throw error;
      }
    },
    [walletService]
  );

  // Pay with card
  const payWithCard = useCallback(
    async (amount, currency, billingDetails) => {
      dispatch({ type: PAYMENT_ACTIONS.CLEAR_ERROR });
      dispatch({ type: PAYMENT_ACTIONS.SET_PROCESSING, payload: true });

      try {
        const result = await cardService.payWithCard(amount, currency, billingDetails);
        dispatch({
          type: PAYMENT_ACTIONS.SET_TRANSACTION_RESULT,
          payload: result,
        });
        return result;
      } catch (error) {
        dispatch({
          type: PAYMENT_ACTIONS.SET_ERROR,
          payload: {
            message: error.message,
            code: error.code,
            declineCode: error.declineCode,
            type: 'card',
          },
        });
        throw error;
      }
    },
    [cardService]
  );

  // Save card
  const saveCard = useCallback(
    async (billingDetails) => {
      dispatch({ type: PAYMENT_ACTIONS.SET_LOADING, payload: true });

      try {
        const result = await cardService.saveCard(billingDetails);
        dispatch({
          type: PAYMENT_ACTIONS.SET_SAVED_CARDS,
          payload: [...state.savedCards, result],
        });
        dispatch({ type: PAYMENT_ACTIONS.SET_LOADING, payload: false });
        return result;
      } catch (error) {
        dispatch({
          type: PAYMENT_ACTIONS.SET_ERROR,
          payload: { message: error.message, type: 'card_save' },
        });
        throw error;
      }
    },
    [cardService, state.savedCards]
  );

  // Restore purchases
  const restorePurchases = useCallback(async () => {
    dispatch({ type: PAYMENT_ACTIONS.SET_LOADING, payload: true });

    try {
      const purchases = await iapService.restorePurchases();
      dispatch({ type: PAYMENT_ACTIONS.SET_LOADING, payload: false });
      return purchases;
    } catch (error) {
      dispatch({
        type: PAYMENT_ACTIONS.SET_ERROR,
        payload: { message: error.message, type: 'restore' },
      });
      throw error;
    }
  }, [iapService]);

  // Clear error
  const clearError = useCallback(() => {
    dispatch({ type: PAYMENT_ACTIONS.CLEAR_ERROR });
  }, []);

  // Clear last transaction
  const clearTransaction = useCallback(() => {
    dispatch({ type: PAYMENT_ACTIONS.CLEAR_TRANSACTION });
  }, []);

  // Set up IAP listeners
  useEffect(() => {
    const removePurchaseListener = iapService.addPurchaseListener((event) => {
      if (event.type === 'PURCHASE_SUCCESS') {
        dispatch({
          type: PAYMENT_ACTIONS.SET_TRANSACTION_RESULT,
          payload: {
            success: true,
            type: 'iap',
            productId: event.purchase.productId,
            transactionId: event.purchase.transactionId,
            timestamp: Date.now(),
          },
        });
      }
    });

    const removeErrorListener = iapService.addErrorListener((event) => {
      dispatch({
        type: PAYMENT_ACTIONS.SET_ERROR,
        payload: {
          message: event.error?.message || 'Purchase failed',
          type: event.type,
        },
      });
    });

    return () => {
      removePurchaseListener();
      removeErrorListener();
    };
  }, [iapService]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      iapService.dispose();
    };
  }, [iapService]);

  const contextValue = {
    ...state,
    initializePayments,
    purchaseProduct,
    purchaseSubscription,
    payWithWallet,
    payWithCard,
    saveCard,
    restorePurchases,
    clearError,
    clearTransaction,
  };

  return (
    <StripeProvider
      publishableKey={PaymentConfig.stripe.publishableKey}
      merchantIdentifier={PaymentConfig.stripe.merchantId}
      urlScheme={PaymentConfig.stripe.urlScheme}
    >
      <PaymentContext.Provider value={contextValue}>
        {children}
      </PaymentContext.Provider>
    </StripeProvider>
  );
}

export function usePayment() {
  const context = useContext(PaymentContext);
  if (!context) {
    throw new Error('usePayment must be used within a PaymentProvider');
  }
  return context;
}

export { PaymentContext };

